framework_css:
:root {
  /* Color system */
  --color-black: #000000;
  --color-white: #FFFFFF;
  --color-border: #E0E0E0;
  --color-facebook: #3B5998;
  --color-instagram: #E1306C;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --max-width: 1120px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-black);
  background-color: var(--color-white);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
 a:focus {
  text-decoration: underline;
}

.page {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  max-width: var(--max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-5);
  padding-right: var(--space-5);
}

/* Header */

.site-header {
  padding-top: var(--space-6);
  padding-bottom: var(--space-2);
  text-align: center;
}

.header-inner {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.site-logo {
  display: inline-flex;
  align-items: flex-end;
  gap: var(--space-2);
  font-family: var(--font-heading);
  color: var(--color-black);
}

.logo-box {
  background-color: var(--color-black);
  color: var(--color-white);
  padding: var(--space-2) var(--space-4);
  font-size: 32px;
  font-weight: var(--font-weight-bold);
  line-height: 1;
}

.logo-words {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  line-height: var(--line-height-tight);
}

.logo-word-primary {
  font-size: 22px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-weight: var(--font-weight-regular);
}

.logo-word-secondary {
  font-size: 38px;
  font-weight: var(--font-weight-bold);
}

.primary-nav {
  margin-top: var(--space-4);
  margin-bottom: var(--space-4);
}

.primary-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  justify-content: center;
  gap: 32px;
  flex-wrap: nowrap;
}

.primary-nav-item a {
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: var(--font-weight-regular);
  text-transform: lowercase;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus {
  text-decoration: underline;
}

.header-divider {
  border: 0;
  border-bottom: 1px solid var(--color-border);
  margin: 0;
}

/* Social sidebar (visual-only, non-interactive) */

.social-sidebar {
  position: fixed;
  top: 50%;
  right: var(--space-5);
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
  z-index: 10;
}

.social-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-size: 18px;
  font-weight: var(--font-weight-medium);
  background-color: var(--color-white);
}

.social-circle--facebook {
  border: 2px solid var(--color-facebook);
  color: var(--color-facebook);
}

.social-circle--instagram {
  border: 2px solid var(--color-instagram);
  color: var(--color-instagram);
}

/* Main content area */

.site-main {
  flex: 1;
  padding-top: var(--space-6);
  padding-bottom: var(--space-7);
}

/* Footer */

.site-footer {
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
  font-size: var(--font-size-small);
}

.footer-divider {
  border: 0;
  border-top: 1px solid var(--color-border);
  margin: 0;
}

.footer-inner {
  padding-top: var(--space-4);
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0 0 var(--space-3);
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 10px 24px;
}

.footer-nav-item a {
  text-transform: none;
  letter-spacing: 0.04em;
  font-weight: var(--font-weight-regular);
}

.footer-nav-item a:hover,
.footer-nav-item a:focus {
  text-decoration: underline;
}

.footer-meta {
  text-align: center;
  color: #555555;
}

.footer-copy {
  margin: 0;
}

/* Responsive adjustments */

@media (max-width: 900px) {
  .container {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .primary-nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-2);
    column-gap: var(--space-3);
  }
}

@media (max-width: 600px) {
  .site-header {
    padding-top: var(--space-5);
  }

  .logo-box {
    font-size: 26px;
    padding: var(--space-2) var(--space-3);
  }

  .logo-word-primary {
    font-size: 18px;
  }

  .logo-word-secondary {
    font-size: 30px;
  }

  .social-sidebar {
    right: var(--space-3);
  }
}
